import{_ as t,o as n,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const o="/assets/esp32c3-pcb-layout-example.CDovavQM.png",s="/assets/shared-stackup-design__en.CwsNlpbn.png",i="/assets/esp32c3-pcb-rf-layout.BdCmS1OP.png",l="/assets/esp32c3-pcb-stub-layout.Bg5CBp-E.png",d="/assets/5-9.BaGWgiCW.png",c="/assets/5-10.Btur6b5D.jpg",p="/assets/Figure_5_Distances_H_T_A_B_used_to_estimate_impedance_of_antenna_trace.5e8e1e6d22f7e.2zH_gF6t.png",g="/assets/esp32c3-module-place-on-base-board-right.CBP3nk2A.png",h="/assets/esp32c3-module-clearance.CGtQb-lI.png",u="/assets/Figure_1_Antenna_with_directions_clear.5e8e1df21085f.CvyvzHLJ.png",m="/assets/Figure_2_Examples_two_antennas_placed_for_diversity.5e8e1e0e9bdda.BZYOWMbw.png",f="/assets/Figure_3_Clearout_area_with_additional_clearance_below_the_ground.5e8e1e2dc303f.YEl1GtD0.png",b="/assets/Figure_4_A_line_at_an_angle_of_8_degrees___safe_distance.5e8e1e4cd2e42.Bhh9Dh-T.png",S=JSON.parse('{"title":"ESP32 / 2.4 GHz RF, Antenna, and PCB Layout References","description":"Curated bibliography and layout guidelines from vendor app notes, FCC filings, and Espressif hardware design docs (imported 2026-05-26).","frontmatter":{"title":"ESP32 / 2.4 GHz RF, Antenna, and PCB Layout References","description":"Curated bibliography and layout guidelines from vendor app notes, FCC filings, and Espressif hardware design docs (imported 2026-05-26)."},"headers":[],"relativePath":"microcontrollers-and-socs/esp32/esp32-2-4ghz-rf-antenna-pcb-layout-references.md","filePath":"microcontrollers-and-socs/esp32/esp32-2-4ghz-rf-antenna-pcb-layout-references.md"}'),_={name:"microcontrollers-and-socs/esp32/esp32-2-4ghz-rf-antenna-pcb-layout-references.md"};function C(y,e,w,P,F,k){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="esp32-2-4-ghz-rf-antenna-and-pcb-layout-references" tabindex="-1">ESP32 / 2.4 GHz RF, Antenna, and PCB Layout References <a class="header-anchor" href="#esp32-2-4-ghz-rf-antenna-and-pcb-layout-references" aria-label="Permalink to &quot;ESP32 / 2.4 GHz RF, Antenna, and PCB Layout References&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage + PDF (multi-source bibliography)</li><li>Origin: user-provided URL list (10 sources)</li><li>Imported: 2026-05-26</li></ul><h3 id="primary-links" tabindex="-1">Primary links <a class="header-anchor" href="#primary-links" aria-label="Permalink to &quot;Primary links&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Document</th><th>URL</th></tr></thead><tbody><tr><td>1</td><td>TI SWRA117D — Small Size 2.4 GHz PCB antenna (IFA)</td><td><a href="https://www.ti.com/lit/an/swra117d/swra117d.pdf" target="_blank" rel="noreferrer">https://www.ti.com/lit/an/swra117d/swra117d.pdf</a></td></tr><tr><td>2</td><td>Espressif — ESP32-C3 hardware design guidelines (PCB layout, RF)</td><td><a href="https://docs.espressif.com/projects/esp-hardware-design-guidelines/en/latest/esp32c3/pcb-layout-design.html" target="_blank" rel="noreferrer">https://docs.espressif.com/projects/esp-hardware-design-guidelines/en/latest/esp32c3/pcb-layout-design.html</a></td></tr><tr><td>3</td><td>FCC — CrossAir CA-C03 SMD antenna (2A7IN-PM016)</td><td><a href="https://fcc.report/FCC-ID/2A7IN-PM016/6344297.pdf" target="_blank" rel="noreferrer">https://fcc.report/FCC-ID/2A7IN-PM016/6344297.pdf</a></td></tr><tr><td>4</td><td>Espressif — ESP-WROOM-02 PCB design and module placement</td><td><a href="https://www.espressif.com/sites/default/files/documentation/esp-wroom-02_pcb_design_and_module_placement_guide_0.pdf" target="_blank" rel="noreferrer">https://www.espressif.com/sites/default/files/documentation/esp-wroom-02_pcb_design_and_module_placement_guide_0.pdf</a></td></tr><tr><td>5</td><td>Johanson Technology — Chip antenna layout (802.11)</td><td><a href="https://www.johansontechnology.com/docs/2/jti-antenna-mounting.pdf" target="_blank" rel="noreferrer">https://www.johansontechnology.com/docs/2/jti-antenna-mounting.pdf</a></td></tr><tr><td>6</td><td>Infineon AN91445 — Antenna design and RF layout guidelines</td><td><a href="https://www.infineon.com/dgdl/Infineon-AN91445_Antenna_Design_and_RF_Layout_Guidelines-ApplicationNotes-v09_00-EN.pdf" target="_blank" rel="noreferrer">https://www.infineon.com/dgdl/Infineon-AN91445_Antenna_Design_and_RF_Layout_Guidelines-ApplicationNotes-v09_00-EN.pdf</a></td></tr><tr><td>7</td><td>Espressif — ESP32-C3 book, §5.2.5 RF and antenna</td><td><a href="https://espressif.github.io/esp32-c3-book-en/chapter_5/5.2/5.2.5.html" target="_blank" rel="noreferrer">https://espressif.github.io/esp32-c3-book-en/chapter_5/5.2/5.2.5.html</a></td></tr><tr><td>8</td><td>FCC — CrossAir CA-C03 (2ASYE-T-ECHO filing)</td><td><a href="https://fcc.report/FCC-ID/2ASYE-T-ECHO/6227962.pdf" target="_blank" rel="noreferrer">https://fcc.report/FCC-ID/2ASYE-T-ECHO/6227962.pdf</a></td></tr><tr><td>9</td><td>Antenova / Microwaves &amp; RF — Embedded antenna PCB placement</td><td><a href="https://www.mwrf.com/technologies/embedded/systems/article/21128361/antenova-design-tips-for-positioning-an-embedded-antenna-on-a-pcb" target="_blank" rel="noreferrer">https://www.mwrf.com/technologies/embedded/systems/article/21128361/antenova-design-tips-for-positioning-an-embedded-antenna-on-a-pcb</a></td></tr><tr><td>10</td><td>NXP UM10992 — BLE antenna design guide</td><td><a href="https://www.nxp.com/docs/en/user-guide/UM10992.pdf" target="_blank" rel="noreferrer">https://www.nxp.com/docs/en/user-guide/UM10992.pdf</a></td></tr></tbody></table><p><strong>Figures in this note:</strong> 14 images saved under <code>microcontrollers-and-socs/esp32/assets/esp32-rf-antenna-pcb-layout-20260526/</code> (Espressif HW guidelines, ESP32-C3 book, Antenova article). Diagrams inside the PDFs above are not duplicated here—open the linked PDFs for full figures (TI IFA dimensions, WROOM placement options, Infineon Smith chart, Johanson layout drawings, FCC radiation patterns, NXP antenna examples).</p><hr><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h3 id="when-to-use-which-source" tabindex="-1">When to use which source <a class="header-anchor" href="#when-to-use-which-source" aria-label="Permalink to &quot;When to use which source&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Goal</th><th>Start here</th></tr></thead><tbody><tr><td>ESP32-C3 module on custom PCB (layers, RF trace, keepout)</td><td>Espressif HW guidelines (#2), ESP32-C3 book (#7)</td></tr><tr><td>ESP-WROOM-02 / classic module at board edge</td><td>Espressif WROOM placement guide (#4)</td></tr><tr><td>On-board IFA / meander 2.4 GHz antenna geometry</td><td>TI SWRA117D (#1)</td></tr><tr><td>Ceramic / SMD chip antenna part + matching</td><td>FCC CA-C03 (#3, #8), Johanson (#5)</td></tr><tr><td>General BLE matching, chip vs PCB antenna tradeoffs</td><td>NXP UM10992 (#10), Infineon AN91445 (#6)</td></tr><tr><td>Mechanical placement, keep-out, transmission line</td><td>Antenova article (#9)</td></tr></tbody></table><hr><h3 id="pcb-stack-and-ground" tabindex="-1">PCB stack and ground <a class="header-anchor" href="#pcb-stack-and-ground" aria-label="Permalink to &quot;PCB stack and ground&quot;">​</a></h3><p><strong>Espressif ESP32-C3 (four-layer recommended)</strong></p><ul><li>L1: signals + components; L2: solid GND (no signals); L3: power + limited signals over full GND under RF/crystal; L4: minimal routing, no components.</li><li>Two-layer is possible if L2 provides uninterrupted GND under chip, RF, and crystal.</li></ul><p><img src="'+o+'" alt="ESP32-C3 reference PCB layout example"></p><p><img src="'+s+'" alt="Suggested PCB stack-up for 50 Ω RF trace"></p><p><strong>Infineon AN91445 (general BLE):</strong> four-layer preferred; two-layer acceptable with careful ground. Uninterrupted ground under RF from chip through matching network to antenna; split analog/digital grounds only with a single tie at supply—not overlapping RF.</p><hr><h3 id="rf-trace-50-ω-and-matching" tabindex="-1">RF trace (50 Ω) and matching <a class="header-anchor" href="#rf-trace-50-ω-and-matching" aria-label="Permalink to &quot;RF trace (50 Ω) and matching&quot;">​</a></h3><p><strong>Espressif ESP32-C3</strong></p><ul><li>RF trace: 50 Ω, reference plane on layer adjacent to chip; no layer changes on RF path; 135° bends or arcs; consistent width, no branches; dense GND vias along trace.</li><li>CLC (π) matching at chip: 0201, zigzag (capacitors not same orientation); optional <strong>stub</strong> on ground cap near chip for 2nd harmonic (≈15 mil length, 100 Ω ±10% stub Z, via to inner layer, keep-out on L1/L2). Not required for 0402+ packages.</li><li>Extra CLC at PCB antenna for tuning; place at antenna feed.</li></ul><p><img src="'+i+'" alt="ESP32-C3 RF layout (four-layer)"></p><p><img src="'+l+'" alt="Stub in CLC matching circuit"></p><p><strong>ESP32-C3 book:</strong> π-matching (CLC preferred) between <code>LNA_IN</code> and antenna; values depend on antenna and layout. Antenna types: PCB onboard, rod (I-PEX), FPC, ceramic, 3D metal—with tradeoffs in cost, gain, and structure.</p><p><img src="'+d+'" alt="CLC matching for ESP32-C3 RF"></p><p><img src="'+c+'" alt="Commonly used antenna types"></p><p><strong>Antenova / embedded antenna article</strong></p><ul><li>Transmission line must be <strong>50 Ω</strong>; poor match → VSWR, SNR loss, possible receiver desense.</li><li>Keep trace <strong>straight</strong>; vias along both sides of trace for isolation.</li><li>Shorter trace and correct GCPW dimensions (H, T, A, B) improve performance; free calculator: <a href="https://blog.antenova.com/rf-transmission-line-calculator" target="_blank" rel="noreferrer">https://blog.antenova.com/rf-transmission-line-calculator</a></li></ul><p><img src="'+p+'" alt="GCPW trace dimensions H, T, A, B"></p><p><strong>TI SWRA117D (2.4 GHz IFA):</strong> 50 Ω feed at 2.45 GHz; footprint <strong>15.2 × 5.7 mm</strong>; VSWR &lt; 2 over ISM band when copied exactly from reference gerber/DXF. Small dimension changes strongly affect resonance.</p><p><strong>NXP UM10992:</strong> Standard practice—reserve pads for π, T, or L matching; tune with VNA (return loss / Smith chart). Chip antennas: lowest footprint, lowest efficiency; microstrip: low cost, layout-sensitive; metal plate: high efficiency.</p><hr><h3 id="antenna-placement-and-keep-out" tabindex="-1">Antenna placement and keep-out <a class="header-anchor" href="#antenna-placement-and-keep-out" aria-label="Permalink to &quot;Antenna placement and keep-out&quot;">​</a></h3><p><strong>Espressif module on base board</strong></p><ul><li>Prefer module <strong>PCB antenna outside</strong> the base board; feed point near board edge. Options marked ✓ in vendor diagrams are strongly recommended.</li><li>If antenna must stay on board: <strong>≥15 mm clearance</strong> (all directions): no copper, traces, or components; feed closest to edge; cut away base board under antenna if possible.</li><li>UART/USB and high-speed traces <strong>far from antenna</strong>; UART surrounded by GND pour + vias.</li><li>Test housing effect on throughput and range.</li></ul><p><img src="'+g+'" alt="Module placement on base board (feed on right)"></p><p><img src="'+h+'" alt="Antenna keep-out on base board"></p><p><strong>ESP-WROOM-02 (meandered IFA, ~2 dBi)</strong></p><ul><li>Best: edge placement with antenna in free space (options 2–3); ≥5 mm clearance around antenna.</li><li>On-board antenna: option 4 (no copper under antenna) acceptable; option 6 (center, no clearance) worst.</li><li>Options 1–3 show similar TX power/EVM when antenna faces open space.</li></ul><p><strong>Antenova article</strong></p><ul><li><strong>Corner</strong> of PCB is usually best (clearance in five directions; feed in the sixth).</li><li>MIMO: separate antennas on <strong>different corners</strong>.</li><li>Keep-out: no metal on <strong>any layer</strong> in near field; size per datasheet (often antenna size + 1–3 mm below ground).</li><li>Ground plane size affects resonance; route feed <strong>perpendicular</strong> to microstrip so feed cable is not part of the resonator.</li><li>Keep batteries, LCDs, metal connectors (USB/HDMI/Ethernet), and switching supplies away; use <strong>8° line</strong> from antenna base for safe component height clearance.</li><li>Isolate co-located antennas: ≥10 dB to 1 GHz, ≥20 dB to 20 GHz (distance or 90°/180° orientation).</li><li>Plastic enclosures and lossy plastics (e.g. glass-filled nylon) detune; metal cases block radiation.</li></ul><p><img src="'+u+'" alt="Six radiation directions at corner placement"></p><p><img src="'+m+'" alt="Two antennas for diversity"></p><p><img src="'+f+'" alt="Keep-out and ground clearance"></p><p><img src="'+b+'" alt="8° safe distance rule vs tall components"></p><p><strong>Johanson chip antennas</strong></p><ul><li>Specs are on vendor EVB; on-product performance will differ—tune matching from measured S11.</li><li><strong>Do not</strong> place ground plane in immediate proximity (not a ground-dependent design).</li><li>Clearance (horizontal mount): &gt;2 mm from short edges (&gt;1 mm on ground-adjacent short edge); &gt;4 mm from long edge without ground.</li><li>Feedline perpendicular to microstrip; stitch edge ground to bottom plane with many vias.</li><li>Microstrip length + surrounding ground shape → dipole-like (~3–4 × 1–2 cm ground) vs monopole (large ground).</li></ul><hr><h3 id="chip-antenna-example-crossair-ca-c03-fcc" tabindex="-1">Chip antenna example: CrossAir CA-C03 (FCC) <a class="header-anchor" href="#chip-antenna-example-crossair-ca-c03-fcc" aria-label="Permalink to &quot;Chip antenna example: CrossAir CA-C03 (FCC)&quot;">​</a></h3><ul><li>Size: 5.5 × 2.0 × 1.0 mm SMD; 2450 ±50 MHz; 50 Ω; VSWR &lt;2; peak gain ~4.3 dBi; efficiency ~78–82% on vendor test PCB (1.0 mm thick).</li><li>Example match on test board: series 0 Ω, shunt <strong>3 nH</strong>, series 0 Ω (application-specific).</li><li>2.4 GHz operation requires impedance matching network tuning on your PCB.</li></ul><hr><h3 id="power-crystal-and-interference-espressif" tabindex="-1">Power, crystal, and interference (Espressif) <a class="header-anchor" href="#power-crystal-and-interference-espressif" aria-label="Permalink to &quot;Power, crystal, and interference (Espressif)&quot;">​</a></h3><ul><li>RF-related supplies (e.g. VDD3P3 pins 2/3): 10 µF + 0.1/1 µF, CLC/LC filter near pins, 0201, GND isolation from RF/GPIO; ≥9 vias on chip bottom GND pad.</li><li>Crystal: complete GND plane; ≥2 mm from chip; no vias on clock lines; caps at crystal ends; no HF traces under crystal; no magnets nearby.</li><li>Poor TX despite small ripple → often crystal layout, not only PSU; re-layout per crystal section.</li><li>TX power off-target / poor EVM → impedance mismatch; π-match at RF pin.</li><li>Good TX, poor RX → coupling to antenna (crystal harmonics, UART crossing RF, on-board HF noise).</li></ul><hr><h3 id="pcb-ifa-reference-ti" tabindex="-1">PCB IFA reference (TI) <a class="header-anchor" href="#pcb-ifa-reference-ti" aria-label="Permalink to &quot;PCB IFA reference (TI)&quot;">​</a></h3><ul><li>Meandered IFA for 2.4 GHz ISM; copy gerber/DXF from CC2511 USB dongle ref design for best results.</li><li>Key dimensions (mm): L1 3.94, L2 2.70, L3 5.00, L4 2.64, L5 2.00, L6 4.90, W1 0.90, W2 0.50, etc. (full table in PDF).</li><li>Ground plane size shifts resonance (e.g. USB plugged into laptop narrows bandwidth but still covers ISM).</li><li>Measured on dongle ref: ~4.5 dBi peak gain (XY), LOS range ~240 m @ 250 kbps 1% PER (platform-specific).</li></ul><hr><h3 id="infineon-an91445-highlights" tabindex="-1">Infineon AN91445 highlights <a class="header-anchor" href="#infineon-an91445-highlights" aria-label="Permalink to &quot;Infineon AN91445 highlights&quot;">​</a></h3><ul><li>Antenna + matching + layout dominate BLE range more than silicon choice.</li><li>Quarter-wave monopole on PCB ground is common; feed is single-ended, return path is critical.</li><li>Cypress-tested low-cost PCB antennas: MIFA and IFA patterns with feed/length rules in app note.</li><li>Enclosure and ground plane detune; professional antenna tuning with VNA recommended for production.</li><li>RF passives: prefer high-Q inductors at RF; capacitor self-resonance above operating band.</li><li>Wi-Fi coexistence: spatial, frequency, and temporal isolation strategies.</li></ul><hr><h3 id="testing-and-compliance" tabindex="-1">Testing and compliance <a class="header-anchor" href="#testing-and-compliance" aria-label="Permalink to &quot;Testing and compliance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>Notes</th></tr></thead><tbody><tr><td>ESP32-C3 book</td><td>Conducted: 50 Ω cable from RF port to tester; radiated: antennas ~10 cm apart in shield box. Key Wi-Fi metrics: TX power, EVM, RX sensitivity, freq error (tables in book).</td></tr><tr><td>NXP UM10992</td><td>VNA calibration, return loss, bandwidth, Smith chart, matching network design procedure.</td></tr><tr><td>TI SWRA117D</td><td>Reflection, radiation patterns, harmonic/spurious vs ETSI/FCC limits; plastic encapsulation shifts resonance lower.</td></tr></tbody></table><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Treat <strong>50 Ω RF routing</strong>, <strong>continuous ground under RF</strong>, and <strong>matching (CLC/π)</strong> as one system; tune on your stackup and antenna, not only from reference BOM values.</li><li><strong>Placement beats BOM</strong>: edge/corner antenna with full keep-out (≥15 mm for Espressif modules, datasheet + 1–3 mm for chip antennas) usually matters more than a better module SKU in a bad layout.</li><li>Keep <strong>UART/USB, crystals, DDR, and power switching</strong> away from the antenna and RF trace; stub and filter practices on Espressif C3 targets harmonic and supply coupling.</li><li><strong>Chip antennas</strong> (CA-C03, Johanson, etc.) need application-specific matching and vendor EVB is only a starting point; verify S11 and radiation on your PCB.</li><li>Use <strong>FCC grant PDFs</strong> for certified part baseline specs; still re-test on your board for regulatory and link budget.</li><li>For certification-ready products, plan <strong>VNA tuning</strong>, shield-box radiated tests, and enclosure validation early—not after mechanical design is frozen.</li></ul>',65)])])}const E=t(_,[["render",C]]);export{S as __pageData,E as default};
